// Tests for Docker image validation behavior when Docker is not available.
// Verifies that validation degrades gracefully without producing errors/warnings.

package workflow

import (
	"os/exec"
	"testing"
)

// TestValidateDockerImage_SkipsWhenDockerNotAvailable verifies that
// validateDockerImage returns nil (skip validation) when the Docker CLI
// is not installed. This ensures no spurious warnings in environments
// like ubuntu-slim CI runners.
func TestValidateDockerImage_SkipsWhenDockerNotAvailable(t *testing.T) {
	// Only run this test if Docker is not installed on the system.
	// When Docker IS installed, we skip since we can't test the "not installed" path.
	if _, err := exec.LookPath("docker"); err == nil {
		t.Skip("docker is installed, cannot test 'docker not installed' path")
	}

	// validateDockerImage should return nil (skip validation silently)
	err := validateDockerImage("alpine:latest", false)
	if err != nil {
		t.Errorf("expected nil error when Docker is not available (graceful skip), got: %v", err)
	}
}

// TestValidateDockerImage_SkipsWhenDaemonNotRunning verifies that
// validateDockerImage returns nil (skip validation) when the Docker daemon
// is not running. This ensures no spurious warnings on developer machines
// where Docker Desktop is installed but not started.
func TestValidateDockerImage_SkipsWhenDaemonNotRunning(t *testing.T) {
	// Only run this test if Docker is installed but daemon is not running.
	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not installed, cannot test daemon-not-running path")
	}
	if isDockerDaemonRunning() {
		t.Skip("docker daemon is running, cannot test 'daemon not running' path")
	}

	// validateDockerImage should return nil (skip validation silently)
	err := validateDockerImage("alpine:latest", false)
	if err != nil {
		t.Errorf("expected nil error when Docker daemon is not running (graceful skip), got: %v", err)
	}
}

